1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_DISCOUNT = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
6	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
7	const BLOCK_OF_THREE_DISCOUNT = 15;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const INSURANCE_VALUE: Record<string, number> = {
19	  sword: 1000,
20	  amulet: 600,
21	  staff: 800,
22	  potion: 400,
23	  rune: 250,
24	  moonstone: 250,
25	};
26	
27	const CAP_MULTIPLIER = 2;
28	
29	type Item = { type: string; cursed?: boolean; enchantment?: number };
30	type QuoteStep = { op: "quote"; items: Array<Item> };
31	type Damage = { itemType: string; amount: number };
32	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
33	type Step = QuoteStep | ClaimStep;
34	type Customer = { yearsWithMHPCO: number };
35	type Scenario = {
36	  customer: Customer;
37	  steps: Array<Step>;
38	};
39	
40	const roundDownInMHPCOFavor = (amount: number): number =>
41	  Math.floor(amount + FLOAT_ROUNDING_TOLERANCE);
42	
43	const roundUpInMHPCOFavor = (amount: number): number =>
44	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
45	
46	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
47	
48	const insuranceValueOf = (item: Item): number => INSURANCE_VALUE[item.type];
49	
50	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
53	
54	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
55	  { applies: (item) => item.cursed === true, rate: 0.5 },
56	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD, rate: 0.3 },
57	];
58	
59	const surchargesFor = (item: Item): number =>
60	  ITEM_SURCHARGES.reduce(
61	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
62	    0,
63	  );
64	
65	const sumOfBasePrices = (items: Array<Item>): number =>
66	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
67	
68	const sumOfItemSurcharges = (items: Array<Item>): number =>
69	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
70	
71	const COMPONENT_TYPES = ["rune", "moonstone"];
72	const BLOCK_SIZE = 3;
73	
74	const countOfType = (items: Array<Item>, type: string): number =>
75	  items.filter((item) => item.type === type).length;
76	
77	const formsABlock = (items: Array<Item>, type: string): boolean =>
78	  countOfType(items, type) === BLOCK_SIZE;
79	
80	const blockDiscountFor = (items: Array<Item>): number =>
81	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
82	  BLOCK_OF_THREE_DISCOUNT;
83	
84	const basePremiumFor = (items: Array<Item>): number =>
85	  sumOfBasePrices(items) - blockDiscountFor(items);
86	
87	type PolicyContext = { customer: Customer; isFollowUp: boolean };
88	type PolicyAdjustment = { applies: (ctx: PolicyContext) => boolean; signedRate: number };
89	
90	const POLICY_ADJUSTMENTS: Array<PolicyAdjustment> = [
91	  { applies: () => true, signedRate: +FIRST_INSURANCE_SURCHARGE },
92	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, signedRate: -LOYALTY_DISCOUNT },
93	  { applies: ({ isFollowUp }) => isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT },
94	];
95	
96	const policyAdjustmentsOn = (policyBase: number, ctx: PolicyContext): number =>
97	  POLICY_ADJUSTMENTS.reduce(
98	    (sum, { applies, signedRate }) => sum + (applies(ctx) ? policyBase * signedRate : 0),
99	    0,
100	  );
101	
102	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
103	  const policyBase = basePremiumFor(step.items);
104	  const premiumBeforeRounding =
105	    policyBase
106	    + policyAdjustmentsOn(policyBase, ctx)
107	    + sumOfItemSurcharges(step.items)
108	    + PROCESSING_FEE;
109	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
110	};
111	
112	const DEDUCTIBLE = 100;
113	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
114	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
115	
116	const findInsuredItem = (policy: QuoteStep, itemType: string): Item =>
117	  policy.items.find((item) => item.type === itemType)!;
118	
119	const reimbursementOf = (item: Item, damage: Damage): number =>
120	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
121	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
122	    : damage.amount;
123	
124	const payoutForDamage = (item: Item, damage: Damage): number =>
125	  reimbursementOf(item, damage) - DEDUCTIBLE;
126	
127	const sumOfInsuranceValues = (items: Array<Item>): number =>
128	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
129	
130	const capFor = (policy: QuoteStep): number =>
131	  CAP_MULTIPLIER * sumOfInsuranceValues(policy.items);
132	
133	const claimStep = (
134	  step: ClaimStep,
135	  policy: QuoteStep,
136	  remainingCap: number,
137	): { payout: number; remainingCap: number } => {
138	  const payoutBeforeRounding = step.incident.damages.reduce(
139	    (sum, damage) => sum + payoutForDamage(findInsuredItem(policy, damage.itemType), damage),
140	    0,
141	  );
142	  const desiredPayout = roundDownInMHPCOFavor(payoutBeforeRounding);
143	  const payout = Math.min(desiredPayout, remainingCap);
144	  return { payout, remainingCap: remainingCap - payout };
145	};
146	
147	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
148	
149	export const processScenario = (scenario: unknown): unknown => {
150	  const { customer, steps } = scenario as Scenario;
151	  const remainingCapByPolicy = new Map<number, number>();
152	  const results = steps.map((step, index) => {
153	    if (isQuoteStep(step)) {
154	      return quoteStep(step, { customer, isFollowUp: index > 0 });
155	    }
156	    const policy = steps[step.policy] as QuoteStep;
157	    const currentCap = remainingCapByPolicy.get(step.policy) ?? capFor(policy);
158	    const result = claimStep(step, policy, currentCap);
159	    remainingCapByPolicy.set(step.policy, result.remainingCap);
160	    return result;
161	  });
162	  return { results };
163	};
